+                cx,
+                &block_dev,
+                &mut alloc,
+                parent,
+                &parent_inode,
+                name,
+                ino,
+                Ext4FileType::Symlink,
+                csum_seed,
+                tstamp_secs,
+                tstamp_nanos,
+            )?;
