+
+        debug!(
+            target: "ffs::write",
+            op = "fallocate",
+            ino = ino.0,
+            offset,
+            length,
+            mode,
+            keep_size,
+            punch_hole,
+            size = inode.size,
+            blocks = inode.blocks,
+            "fallocate completed"
+        );
+
+        Ok(())
+    }
