+    fn statfs(&self, _cx: &Cx, _ino: InodeNumber) -> ffs_error::Result<FsStat> {
+        match &self.flavor {
+            FsFlavor::Ext4(sb) => {
+                let blocks_free = sb.free_blocks_count;
+                let blocks_available = blocks_free.saturating_sub(sb.reserved_blocks_count);
