+        if data.is_empty() {
+            return;
+        }
+        let mut guard = match self.pending.lock() {
+            Ok(guard) => guard,
+            Err(poisoned) => poisoned.into_inner(),
+        };
+        guard.insert((ino.0, offset), data);
+        while guard.len() > self.max_pending {
+            if let Some(key) = guard.keys().next().copied() {
+                let _ = guard.remove(&key);
+            } else {
+                break;
+            }
+        }
+        drop(guard);
+    }
